import pytest

def count_vowels(s: str) -> int:
    return sum(1 for c in s.lower() if c in 'aeiou')

# Happy path tests
def test_count_vowels_basic():
    assert count_vowels("hello") == 2  # e, o
    assert count_vowels("aeiou") == 5
    assert count_vowels("HELLO") == 2  # case insensitive
    assert count_vowels("aBcDeFgHi") == 3  # a, e, i

def test_count_vowels_with_spaces_and_punctuation():
    assert count_vowels("hello world") == 3  # e, o, o
    assert count_vowels("hello!") == 2  # e, o
    assert count_vowels("h3llo") == 2  # e, o (numbers ignored)

# Edge case tests
def test_count_vowels_empty_string():
    assert count_vowels("") == 0

def test_count_vowels_no_vowels():
    assert count_vowels("bcdfg") == 0
    assert count_vowels("rhythm") == 0  # y is not considered a vowel

def test_count_vowels_only_vowels():
    assert count_vowels("AEIOUaeiou") == 10

def test_count_vowels_mixed_case():
    assert count_vowels("AeIoU") == 5

# Error case tests
def test_count_vowels_non_string_int():
    with pytest.raises(AttributeError):
        count_vowels(123)

def test_count_vowels_non_string_none():
    with pytest.raises(AttributeError):
        count_vowels(None)

def test_count_vowels_non_string_list():
    with pytest.raises(AttributeError):
        count_vowels([1, 2, 3])

def test_count_vowels_non_string_float():
    with pytest.raises(AttributeError):
        count_vowels(1.5)
